"""Common utilities for agentic AI examples."""import osimport asyncioimport randomfrom typing import Any, Optionalimport anthropic as anthropic_sdkfrom autogen_agentchat.ui import Consolefrom autogen_ext.models.anthropic import AnthropicChatCompletionClientfrom dotenv import load_dotenv# Load environment variablesload_dotenv()def get_required_env(key: str) -> str:    """Get required environment variable or raise error if not found."""    value = os.getenv(key)    if not value:        raise RuntimeError(f"{key} environment variable not found")    return valuedef get_optional_env(key: str, default: str = "") -> str:    """Get optional environment variable with default value."""    return os.getenv(key, default)def load_system_message(filename: str) -> str:    """Load system message from file."""    try:        with open(filename, "r", encoding="utf-8") as f:            return f.read().strip()    except FileNotFoundError:        raise RuntimeError(f"System message file '{filename}' not found")    except Exception as e:        raise RuntimeError(f"Error reading system message file '{filename}': {e}")async def run_with_retry(team: Any, task: Any, max_retries: int = 5) -> None:    """Run a team task with exponential backoff retry for rate limits."""    for attempt in range(max_retries):        try:            await Console(team.run_stream(task=task))            return        except anthropic_sdk.RateLimitError:            if attempt == max_retries - 1:                raise            wait = (2**attempt) + random.uniform(0, 1)            print(f"[Rate Limited] Retry {attempt + 1}/{max_retries} in {wait:.1f}s...")            await asyncio.sleep(wait)def validate_api_key(api_key: Optional[str] = None) -> str:    """Validate and return API key."""    if api_key is None:        api_key = os.getenv("ANTHROPIC_API_KEY")    if not api_key:        raise RuntimeError(            "ANTHROPIC_API_KEY not found. "            "Please set it in your .env file or environment variables."        )    return api_keydef create_anthropic_client(model: str, **kwargs) -> AnthropicChatCompletionClient:    """    Create an Anthropic chat completion client with the specified model.    Args:        model: The model name (e.g., "claude-sonnet-4-6", "claude-haiku-4-5")        **kwargs: Additional parameters to pass to AnthropicChatCompletionClient    Returns:        AnthropicChatCompletionClient instance    Raises:        RuntimeError: If ANTHROPIC_API_KEY environment variable is not found    """    api_key = get_required_env("ANTHROPIC_API_KEY")    return AnthropicChatCompletionClient(        model=model, api_key=api_key, **kwargs    )# Common model constants for easy referenceclass AnthropicModels:    """Common Anthropic model names."""    HAIKU = "claude-haiku-4-5-20251001"    SONNET = "claude-sonnet-4-6"    OPUS = "claude-opus-3-5"